import{_ as t,H as c,f as o,i as r}from"./chunks/framework.nN4pLK1d.js";const p=JSON.parse('{"title":"Elements","description":"","frontmatter":{},"headers":[],"relativePath":"packages/rcml/email/concepts/basic/elements.md","filePath":"packages/rcml/email/concepts/basic/elements.md"}'),a={name:"packages/rcml/email/concepts/basic/elements.md"};function d(l,e,s,i,n,m){return c(),o("div",null,[...e[0]||(e[0]=[r('<h1>Elements</h1><p>Content elements are the leaf nodes of an RCML document — they live inside <code>&lt;rc-column&gt;</code> and render the visible parts of the email.</p><h2 id="element-overview" tabindex="-1">Element overview <a class="header-anchor" href="#element-overview" aria-label="Permalink to &quot;Element overview&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Element</th><th>Purpose</th></tr></thead><tbody><tr><td><a href="/rule-io-sdk/latest/packages/rcml/email/rcml/body/content/rc-text.html"><code>&lt;rc-text&gt;</code></a></td><td>Rich-text paragraph block. Supports paragraphs, lists, inline marks, and placeholders.</td></tr><tr><td><a href="/rule-io-sdk/latest/packages/rcml/email/rcml/body/content/rc-heading.html"><code>&lt;rc-heading&gt;</code></a></td><td>Heading block (h1–h6 semantics).</td></tr><tr><td><a href="/rule-io-sdk/latest/packages/rcml/email/rcml/body/content/rc-button.html"><code>&lt;rc-button&gt;</code></a></td><td>Call-to-action button with a single-line label.</td></tr><tr><td><a href="/rule-io-sdk/latest/packages/rcml/email/rcml/body/content/rc-image.html"><code>&lt;rc-image&gt;</code></a></td><td>Responsive image with optional link.</td></tr><tr><td><a href="/rule-io-sdk/latest/packages/rcml/email/rcml/body/content/rc-logo.html"><code>&lt;rc-logo&gt;</code></a></td><td>Brand logo image.</td></tr><tr><td><a href="/rule-io-sdk/latest/packages/rcml/email/rcml/body/content/rc-video.html"><code>&lt;rc-video&gt;</code></a></td><td>Video thumbnail with play-button overlay.</td></tr><tr><td><a href="/rule-io-sdk/latest/packages/rcml/email/rcml/body/content/rc-spacer.html"><code>&lt;rc-spacer&gt;</code></a></td><td>Invisible vertical whitespace.</td></tr><tr><td><a href="/rule-io-sdk/latest/packages/rcml/email/rcml/body/content/rc-divider.html"><code>&lt;rc-divider&gt;</code></a></td><td>Horizontal rule.</td></tr><tr><td><a href="/rule-io-sdk/latest/packages/rcml/email/rcml/body/content/rc-social.html"><code>&lt;rc-social&gt;</code></a></td><td>Row of social-network icon links.</td></tr><tr><td><a href="/rule-io-sdk/latest/packages/rcml/email/rcml/body/content/rc-raw.html"><code>&lt;rc-raw&gt;</code></a></td><td>Arbitrary HTML injected verbatim.</td></tr></tbody></table><h2 id="content-shapes" tabindex="-1">Content shapes <a class="header-anchor" href="#content-shapes" aria-label="Permalink to &quot;Content shapes&quot;">​</a></h2><p>Elements carry their content in one of three ways:</p><p><strong><code>content</code></strong> — a ProseMirror JSON document, produced from RFM text using <code>rfmToJson()</code> or <code>inlineRfmToJson()</code>. Used by <code>rc-text</code>, <code>rc-heading</code>, and <code>rc-button</code>. See <a href="/rule-io-sdk/latest/packages/rcml/email/concepts/basic/rich-text-content.html">Rich text content</a>.</p><p><strong><code>children</code></strong> — an array of child element objects. Used by <code>rc-social</code>, which holds <code>&lt;rc-social-element&gt;</code> children.</p><p><strong>Attributes only</strong> — no <code>content</code> or <code>children</code>; all data lives in <code>attributes</code>. Used by <code>rc-image</code>, <code>rc-logo</code>, <code>rc-video</code>, <code>rc-spacer</code>, <code>rc-divider</code>, and <code>rc-raw</code>.</p><p>The three shapes reflect different content models. Rich text (<code>rc-text</code>, <code>rc-heading</code>, <code>rc-button</code>) needs to carry structured formatting — bold, links, merge tags — in a form the editor can load and re-edit. A plain string loses that structure; ProseMirror is the editor&#39;s internal document model, so using it as the storage format means documents round-trip through the editor without conversion. <code>rc-social</code> uses <code>children</code> because it is a list of structured items, not prose. Everything else (<code>rc-image</code>, <code>rc-logo</code>, etc.) is pure configuration — their entire &quot;content&quot; is their attribute values.</p><p>Several elements participate in theming passively. <code>rc-button</code> inherits its background colour from the theme&#39;s primary colour slot. <code>rc-text</code> and <code>rc-heading</code> inherit typography from named classes such as <code>rcml-p-style</code> and <code>rcml-h1-style</code> if those classes are applied. <code>rc-logo</code> receives its <code>src</code> from the theme if its <code>rc-class</code> attribute includes <code>rcml-logo-style</code>. See <a href="/rule-io-sdk/latest/packages/rcml/email/concepts/basic/theme.html">Theme</a>.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="/rule-io-sdk/latest/packages/rcml/email/concepts/basic/rich-text-content.html">Rich text content</a> — how RFM produces the <code>content</code> field</li><li><a href="/rule-io-sdk/latest/packages/rcml/email/concepts/basic/containers.html">Containers</a> — the column and section structure that elements live inside</li></ul>',13)])])}const u=t(a,[["render",d]]);export{p as __pageData,u as default};
